const tickets = $input.all().map(item => item.json);
const FIVE_DAYS = 5;
const TEN_DAYS = 10;

const abandonedByClient = [];
const abandonedByAgent = [];
const aging10Days = [];

for (const t of tickets) {
  const ageDays = t.age_days || 0;
  const daysSinceInteraction = t.days_since_interaction || 0;

  const enriched = {
    ticket_number: t.ticket_number,
    title: t.title,
    created_at: t.created_at,
    ageDays,
    agentName: t.agent_name,
    agentEmail: t.agent_email,
    clientName: t.client_name,
    clientEmail: t.client_email,
    buildingName: t.building_name,
    departmentName: t.department_name,
    statusName: t.status_name || '-',
    ticketLink: `https://networkgo.com.br/admin/tickets/${t.ticket_number}`,
    lastCommentAt: t.last_interaction_at || null,
    daysSinceComment: 0,
    lastCommentBy: 'nenhum'
  };

  if (ageDays > TEN_DAYS) {
    aging10Days.push({ ...enriched });
  }

  if (t.last_interaction_at) {
    if (daysSinceInteraction > FIVE_DAYS) {
      enriched.daysSinceComment = daysSinceInteraction;
      if (t.last_interaction_user_id !== t.user_id) {
        enriched.lastCommentBy = 'agente';
        abandonedByClient.push({ ...enriched });
      } else {
        enriched.lastCommentBy = 'cliente';
        abandonedByAgent.push({ ...enriched });
      }
    }
  } else if (ageDays > FIVE_DAYS) {
    enriched.daysSinceComment = ageDays;
    abandonedByAgent.push({ ...enriched });
  }
}

const allUnique = new Set();
for (const t of [...abandonedByClient, ...abandonedByAgent, ...aging10Days]) {
  allUnique.add(t.ticket_number);
}

aging10Days.sort((a, b) => b.ageDays - a.ageDays);
abandonedByAgent.sort((a, b) => b.daysSinceComment - a.daysSinceComment);
abandonedByClient.sort((a, b) => b.daysSinceComment - a.daysSinceComment);

return [{
  json: {
    abandonedByClient,
    abandonedByAgent,
    aging10Days,
    total_alertas: allUnique.size,
    total_abandoned_client: abandonedByClient.length,
    total_abandoned_agent: abandonedByAgent.length,
    total_aging: aging10Days.length,
    total_active_tickets: tickets.length
  }
}];

const data = $input.first().json;
const { abandonedByClient, abandonedByAgent, aging10Days } = data;
const { total_alertas, total_abandoned_client, total_abandoned_agent, total_aging, total_active_tickets } = data;

const now = new Date();

const addToGroup = (group, name, cat) => {
  if (!group[name]) group[name] = { abandonedClient: 0, abandonedAgent: 0, aging: 0, unique: new Set() };
  group[name][cat]++;
};

const byBuilding = {};
for (const t of abandonedByClient) { addToGroup(byBuilding, t.buildingName, 'abandonedClient'); byBuilding[t.buildingName].unique.add(t.ticket_number); }
for (const t of abandonedByAgent) { addToGroup(byBuilding, t.buildingName, 'abandonedAgent'); byBuilding[t.buildingName].unique.add(t.ticket_number); }
for (const t of aging10Days) { addToGroup(byBuilding, t.buildingName, 'aging'); byBuilding[t.buildingName].unique.add(t.ticket_number); }

const byAgent = {};
for (const t of abandonedByClient) { addToGroup(byAgent, t.agentName, 'abandonedClient'); byAgent[t.agentName].unique.add(t.ticket_number); }
for (const t of abandonedByAgent) { addToGroup(byAgent, t.agentName, 'abandonedAgent'); byAgent[t.agentName].unique.add(t.ticket_number); }
for (const t of aging10Days) { addToGroup(byAgent, t.agentName, 'aging'); byAgent[t.agentName].unique.add(t.ticket_number); }

const byDept = {};
for (const t of abandonedByClient) { addToGroup(byDept, t.departmentName, 'abandonedClient'); byDept[t.departmentName].unique.add(t.ticket_number); }
for (const t of abandonedByAgent) { addToGroup(byDept, t.departmentName, 'abandonedAgent'); byDept[t.departmentName].unique.add(t.ticket_number); }
for (const t of aging10Days) { addToGroup(byDept, t.departmentName, 'aging'); byDept[t.departmentName].unique.add(t.ticket_number); }

const agentRanking = Object.entries(byAgent).map(([name, d]) => ({ name, ...d, total: d.unique.size })).sort((a, b) => b.total - a.total);
const buildingEntries = Object.entries(byBuilding).sort((a, b) => b[1].unique.size - a[1].unique.size);
const deptEntries = Object.entries(byDept).sort((a, b) => b[1].unique.size - a[1].unique.size);

const dataGeracao = now.toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit', year: 'numeric', hour: '2-digit', minute: '2-digit' });
const dataRelatorio = now.toLocaleDateString('pt-BR', { weekday: 'long', day: '2-digit', month: 'long', year: 'numeric' });
const dataSubject = now.toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit', year: 'numeric' });
const dataFile = dataSubject.split('/').join('-');

// ===== Helpers comuns =====
const consolRows = (entries, style) => {
  let r = '';
  for (let i = 0; i < entries.length; i++) {
    const [name, d] = entries[i];
    const bg = i % 2 === 0 ? '#fff' : style === 'pdf' ? '#f8fafc' : '#f9fafb';
    if (style === 'pdf') {
      r += `<tr style="background:${bg}"><td style="font-weight:600">${name}</td><td style="text-align:center;color:#0369a1">${d.abandonedClient}</td><td style="text-align:center;color:#dc2626;font-weight:600">${d.abandonedAgent}</td><td style="text-align:center;color:#ca8a04">${d.aging}</td><td style="text-align:center;font-weight:700">${d.unique.size}</td></tr>`;
    } else {
      r += `<tr style="background:${bg};"><td style="padding:12px 16px;border-bottom:1px solid #e5e7eb;font-weight:600;color:#111827;">${name}</td><td style="padding:12px 16px;border-bottom:1px solid #e5e7eb;text-align:center;color:#0369a1;font-weight:600;">${d.abandonedClient}</td><td style="padding:12px 16px;border-bottom:1px solid #e5e7eb;text-align:center;color:#ef4444;font-weight:600;">${d.abandonedAgent}</td><td style="padding:12px 16px;border-bottom:1px solid #e5e7eb;text-align:center;color:#eab308;font-weight:600;">${d.aging}</td><td style="padding:12px 16px;border-bottom:1px solid #e5e7eb;text-align:center;font-weight:700;color:#111827;">${d.unique.size}</td></tr>`;
    }
  }
  return r;
};

const agentRows = (ranking, style) => {
  let r = '';
  for (let i = 0; i < ranking.length; i++) {
    const a = ranking[i];
    const bg = i % 2 === 0 ? '#fff' : style === 'pdf' ? '#f8fafc' : '#f9fafb';
    if (style === 'pdf') {
      r += `<tr style="background:${bg}"><td style="font-weight:600">${a.name}</td><td style="text-align:center;color:#0369a1">${a.abandonedClient}</td><td style="text-align:center;color:#dc2626;font-weight:600">${a.abandonedAgent}</td><td style="text-align:center;color:#ca8a04">${a.aging}</td><td style="text-align:center;font-weight:700">${a.total}</td></tr>`;
    } else {
      r += `<tr style="background:${bg};"><td style="padding:12px 16px;border-bottom:1px solid #e5e7eb;font-weight:600;color:#111827;">${a.name}</td><td style="padding:12px 16px;border-bottom:1px solid #e5e7eb;text-align:center;color:#0369a1;">${a.abandonedClient}</td><td style="padding:12px 16px;border-bottom:1px solid #e5e7eb;text-align:center;color:#ef4444;font-weight:600;">${a.abandonedAgent}</td><td style="padding:12px 16px;border-bottom:1px solid #e5e7eb;text-align:center;color:#eab308;">${a.aging}</td><td style="padding:12px 16px;border-bottom:1px solid #e5e7eb;text-align:center;font-weight:700;color:#111827;">${a.total}</td></tr>`;
    }
  }
  return r;
};

// ===== EMAIL HTML (resumo, sem detalhes) =====
const th = `padding:12px 16px;text-align:left;color:white;font-weight:600;font-size:12px;text-transform:uppercase;letter-spacing:0.5px;`;
const thC = `padding:12px 16px;text-align:center;color:white;font-weight:600;font-size:12px;text-transform:uppercase;letter-spacing:0.5px;`;
const mkT = (hdr, color, rows) => `<div style="margin-bottom:32px;"><h2 style="color:#111827;font-size:18px;font-weight:700;margin:0 0 16px;border-bottom:2px solid ${color};padding-bottom:8px;">${hdr}</h2><div style="overflow:hidden;border-radius:8px;border:1px solid #e5e7eb;"><table style="width:100%;border-collapse:collapse;"><thead><tr style="background:${color};"><th style="${th}">Nome</th><th style="${thC}">Ag.Cli</th><th style="${thC}">S/Resp</th><th style="${thC}">Aging</th><th style="${thC}">Total</th></tr></thead><tbody>${rows}</tbody></table></div></div>`;

const emailHtml = `<!DOCTYPE html><html><head><meta charset="UTF-8"></head><body style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,sans-serif;background-color:#f3f4f6;padding:0;margin:0;"><div style="max-width:900px;margin:0 auto;padding:24px;"><div style="background-color:#fff;border-radius:12px;box-shadow:0 4px 6px -1px rgba(0,0,0,0.1);overflow:hidden;"><div style="background:linear-gradient(135deg,#0c4a6e 0%,#0369a1 50%,#0ea5e9 100%);padding:40px 32px;text-align:center;"><h1 style="color:white;margin:0;font-size:28px;font-weight:700;">Scanner Chamados</h1><p style="color:rgba(255,255,255,0.9);margin:8px 0 0;font-size:16px;">Facilities — ${dataRelatorio}</p></div><div style="padding:32px 32px 0;"><table width="100%" cellpadding="0" cellspacing="8"><tr><td style="width:25%;text-align:center;"><div style="background:#f0f9ff;border:1px solid #bae6fd;padding:20px 8px;border-radius:12px;"><div style="font-size:36px;font-weight:700;color:#0369a1;">${total_alertas}</div><div style="color:#075985;font-size:11px;margin-top:4px;font-weight:600;text-transform:uppercase;">Total Alertas</div></div></td><td style="width:25%;text-align:center;"><div style="background:#f0f9ff;border:1px solid #bae6fd;padding:20px 8px;border-radius:12px;"><div style="font-size:36px;font-weight:700;color:#0284c7;">${total_abandoned_client}</div><div style="color:#075985;font-size:11px;margin-top:4px;font-weight:600;text-transform:uppercase;">Aguard. Cliente</div></div></td><td style="width:25%;text-align:center;"><div style="background:#fef2f2;border:1px solid #fecaca;padding:20px 8px;border-radius:12px;"><div style="font-size:36px;font-weight:700;color:#ef4444;">${total_abandoned_agent}</div><div style="color:#991b1b;font-size:11px;margin-top:4px;font-weight:600;text-transform:uppercase;">Sem Resp. Agente</div></div></td><td style="width:25%;text-align:center;"><div style="background:#fffbeb;border:1px solid #fde68a;padding:20px 8px;border-radius:12px;"><div style="font-size:36px;font-weight:700;color:#eab308;">${total_aging}</div><div style="color:#92400e;font-size:11px;margin-top:4px;font-weight:600;text-transform:uppercase;">Aging > 10d</div></div></td></tr></table></div><div style="padding:32px;">${mkT('Por Unidade','#0369a1',consolRows(buildingEntries,'email'))}${mkT('Por Agente','#075985',agentRows(agentRanking,'email'))}${mkT('Por Departamento','#4b5563',consolRows(deptEntries,'email'))}<div style="background:#f0f9ff;border:1px solid #bae6fd;border-radius:8px;padding:16px 20px;text-align:center;"><p style="margin:0;color:#0369a1;font-size:14px;font-weight:600;">Detalhes completos de todos os ${total_alertas} alertas no PDF em anexo.</p></div></div><div style="background:#f9fafb;padding:24px 32px;border-top:1px solid #e5e7eb;text-align:center;"><p style="margin:0;color:#9ca3af;font-size:12px;">Gerado em ${dataGeracao}</p><p style="margin:6px 0 0;color:#6b7280;font-size:13px;font-weight:600;">NetworkGo — Scanner Chamados</p><p style="margin:4px 0 0;color:#9ca3af;font-size:11px;">Analisados: ${total_active_tickets} | Alertas: ${total_alertas}</p></div></div></div></body></html>`;

// ===== PDF HTML (auditoria completa, paisagem, compacto) =====
const pDetail = (arr, type) => {
  let r = '';
  for (let i = 0; i < arr.length; i++) {
    const t = arr[i];
    const bg = i % 2 === 0 ? '#fff' : '#f8fafc';
    let ti = (t.title || '-').substring(0, 50);
    if ((t.title || '').length > 50) ti += '...';
    if (type === 'aging') {
      const c = t.ageDays > 20 ? '#dc2626' : t.ageDays > 15 ? '#ca8a04' : '#0284c7';
      r += `<tr style="background:${bg}"><td><a href="${t.ticketLink}" style="color:#0369a1;text-decoration:none;font-weight:600">${t.ticket_number}</a></td><td>${ti}</td><td>${t.agentName}</td><td>${t.buildingName}</td><td style="text-align:center;color:${c};font-weight:700">${t.ageDays}d</td></tr>`;
    } else if (type === 'agent') {
      r += `<tr style="background:${bg}"><td><a href="${t.ticketLink}" style="color:#0369a1;text-decoration:none;font-weight:600">${t.ticket_number}</a></td><td>${ti}</td><td style="font-weight:600">${t.agentName}</td><td style="text-align:center;color:#dc2626;font-weight:700">${t.daysSinceComment}d</td><td style="color:#6b7280">${t.lastCommentBy === 'cliente' ? 'Cliente falou' : 'Sem interação'}</td></tr>`;
    } else {
      r += `<tr style="background:${bg}"><td><a href="${t.ticketLink}" style="color:#0369a1;text-decoration:none;font-weight:600">${t.ticket_number}</a></td><td>${ti}</td><td>${t.agentName}</td><td>${t.clientName}</td><td style="text-align:center;color:#0369a1;font-weight:700">${t.daysSinceComment}d</td></tr>`;
    }
  }
  return r;
};

const pdfHtml = `<!DOCTYPE html><html><head><meta charset="UTF-8"><style>*{margin:0;padding:0;box-sizing:border-box}body{font-family:Arial,Helvetica,sans-serif;font-size:9px;color:#1f2937}table{width:100%;border-collapse:collapse}th{padding:4px 6px;text-align:left;color:#fff;font-weight:600;font-size:7px;text-transform:uppercase;letter-spacing:.3px}td{padding:3px 6px;border-bottom:1px solid #e5e7eb;font-size:8px}tr{page-break-inside:avoid}.hdr{background:#0c4a6e;color:#fff;padding:10px 20px;display:flex;justify-content:space-between;align-items:center}.hdr h1{font-size:16px;font-weight:700}.hdr span{font-size:9px;opacity:.8}.kpi{display:flex;gap:8px;padding:8px 20px;background:#f8fafc}.kpi>div{flex:1;text-align:center;padding:6px;border:1px solid #e5e7eb;border-radius:4px;background:#fff}.kpi .v{font-size:18px;font-weight:700}.kpi .l{font-size:6px;text-transform:uppercase;letter-spacing:.3px;color:#6b7280;margin-top:1px}.grid{display:flex;gap:10px;padding:6px 20px}.grid>div{flex:1}.sec{padding:6px 20px}.sec h2{font-size:10px;font-weight:700;margin-bottom:3px;padding-bottom:2px;border-bottom:2px solid}.pb{page-break-before:always}.ft{text-align:center;padding:6px;font-size:7px;color:#9ca3af;border-top:1px solid #e5e7eb;margin-top:6px}</style></head><body><div class="hdr"><h1>Scanner Chamados — Facilities</h1><span>${dataRelatorio} | Gerado ${dataGeracao}</span></div><div class="kpi"><div><div class="v" style="color:#0369a1">${total_alertas}</div><div class="l">Total Alertas</div></div><div><div class="v" style="color:#0284c7">${total_abandoned_client}</div><div class="l">Aguard. Cliente</div></div><div><div class="v" style="color:#dc2626">${total_abandoned_agent}</div><div class="l">Sem Resp. Agente</div></div><div><div class="v" style="color:#ca8a04">${total_aging}</div><div class="l">Aging > 10 dias</div></div><div><div class="v" style="color:#374151">${total_active_tickets}</div><div class="l">Tickets Ativos</div></div></div><div class="grid"><div><div class="sec"><h2 style="border-color:#0369a1">Por Unidade</h2><table><thead><tr style="background:#0369a1"><th>Prédio</th><th style="text-align:center">Ag.Cli</th><th style="text-align:center">S/Resp</th><th style="text-align:center">Aging</th><th style="text-align:center">Total</th></tr></thead><tbody>${consolRows(buildingEntries,'pdf')}</tbody></table></div></div><div><div class="sec"><h2 style="border-color:#075985">Por Agente</h2><table><thead><tr style="background:#075985"><th>Agente</th><th style="text-align:center">Ag.Cli</th><th style="text-align:center">S/Resp</th><th style="text-align:center">Aging</th><th style="text-align:center">Total</th></tr></thead><tbody>${agentRows(agentRanking,'pdf')}</tbody></table></div></div><div><div class="sec"><h2 style="border-color:#4b5563">Por Departamento</h2><table><thead><tr style="background:#4b5563"><th>Depto</th><th style="text-align:center">Ag.Cli</th><th style="text-align:center">S/Resp</th><th style="text-align:center">Aging</th><th style="text-align:center">Total</th></tr></thead><tbody>${consolRows(deptEntries,'pdf')}</tbody></table></div></div></div><div class="pb"></div><div class="sec"><h2 style="border-color:#92400e;color:#92400e">Chamados em Tratamento > 10 dias (${aging10Days.length} chamados)</h2><table><thead><tr style="background:#92400e"><th>Nº</th><th>Título</th><th>Responsável</th><th>Prédio</th><th style="text-align:center">Idade</th></tr></thead><tbody>${pDetail(aging10Days,'aging')}</tbody></table></div><div class="pb"></div><div class="sec"><h2 style="border-color:#dc2626;color:#dc2626">Sem Resposta do Agente (${abandonedByAgent.length} chamados)</h2><table><thead><tr style="background:#dc2626"><th>Nº</th><th>Título</th><th>Responsável</th><th style="text-align:center">Parado</th><th>Situação</th></tr></thead><tbody>${pDetail(abandonedByAgent,'agent')}</tbody></table></div><div class="pb"></div><div class="sec"><h2 style="border-color:#0369a1;color:#0369a1">Aguardando Resposta do Cliente (${abandonedByClient.length} chamados)</h2><table><thead><tr style="background:#0369a1"><th>Nº</th><th>Título</th><th>Responsável</th><th>Cliente</th><th style="text-align:center">Parado</th></tr></thead><tbody>${pDetail(abandonedByClient,'client')}</tbody></table></div><div class="ft">NetworkGo — Scanner Chamados | Analisados: ${total_active_tickets} | Alertas: ${total_alertas} | ${dataGeracao}</div></body></html>`;

return [{
  json: {
    assunto: `[Scanner Chamados] Resumo Diário - Facilities - ${dataSubject}`,
    corpo_html_email: emailHtml,
    corpo_html_pdf: pdfHtml,
    pdfFileName: `Scanner_${dataFile}.pdf`
  }
}];
